CREATE TABLE IF NOT EXISTS `sensitive_access_audit` (
  `id` int AUTO_INCREMENT NOT NULL,
  `userId` int NOT NULL,
  `resourceType` varchar(64) NOT NULL,
  `resourceId` varchar(128) NOT NULL,
  `action` varchar(32) NOT NULL,
  `ipAddress` varchar(45),
  `userAgent` text,
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT `sensitive_access_audit_id` PRIMARY KEY(`id`)
);
CREATE INDEX IF NOT EXISTS `saa_userId_idx` ON `sensitive_access_audit` (`userId`);
CREATE INDEX IF NOT EXISTS `saa_resourceType_idx` ON `sensitive_access_audit` (`resourceType`);
CREATE INDEX IF NOT EXISTS `saa_resourceId_idx` ON `sensitive_access_audit` (`resourceId`);
CREATE INDEX IF NOT EXISTS `saa_createdAt_idx` ON `sensitive_access_audit` (`createdAt`);

